from fastapi import FastAPI
from copilotkit.runtime import LangGraphAgent
from agent.posts_generator_agent import post_generator_workflow
from agent.stack_agent import stack_analyzer_workflow

app = FastAPI()

# Initialize agents
post_generator_agent = LangGraphAgent(workflow=post_generator_workflow)
stack_analyzer_agent = LangGraphAgent(workflow=stack_analyzer_workflow)

# Register agents via FastAPI
@app.post("/copilotkit/post-generator")
async def generate_post(user_prompt: str):
    result = await post_generator_agent.run(user_prompt)
    return {"status": "success", "result": result}

@app.post("/copilotkit/stack-analyzer")
async def analyze_stack(github_url: str):
    result = await stack_analyzer_agent.run(github_url)
    return {"status": "success", "result": result}

@app.get("/")
def health_check():
    return {"status": "agents running"}
